import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Referência de Scalers","description":"","frontmatter":{},"headers":[],"relativePath":"pt/scalers/reference.md","filePath":"pt/scalers/reference.md"}'),d={name:"pt/scalers/reference.md"};function i(n,e,s,l,c,m){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="referencia-de-scalers" tabindex="-1"><i class="ph ph-sliders"></i> Referência de Scalers <a class="header-anchor" href="#referencia-de-scalers" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Referência de Scalers&quot;">​</a></h1><p>Web Adaptive Performance inclui um conjunto de Scalers especializados (módulos de otimização). O Indexer seleciona automaticamente qual Scaler implementar com base no seu impacto visual (<code>Visual Impact</code>) e no tipo de gargalo atual (<code>Target</code>: CPU ou GPU).</p><h2 id="matriz-de-compatibilidade" tabindex="-1">Matriz de Compatibilidade <a class="header-anchor" href="#matriz-de-compatibilidade" aria-label="Permalink to &quot;Matriz de Compatibilidade&quot;">​</a></h2><p>Abaixo está a matriz de compatibilidade e uma descrição de todos os módulos disponíveis.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Scaler</th><th style="text-align:left;">Pipeline</th><th style="text-align:left;">Target</th><th style="text-align:left;">Descrição</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduz a resolução de renderização, diminuindo radicalmente a carga no Fillrate da GPU. <em>Veja os detalhes abaixo.</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Desativa as sombras por fases.<br>Em <strong>URP</strong>, primeiro desativa as sombras suaves, depois as sombras de luzes adicionais e, finalmente, as sombras principais.<br>Em <strong>BiRP</strong>, muda as sombras para o modo <code>Hard Only</code> antes de desativá-las completamente.</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">Reduz o número de cascatas de sombra. Diminui os Draw Calls da CPU e a carga na GPU.</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Encurta a distância de desenho das sombras.</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduz a resolução dos mapas de sombra (Shadow Maps).</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Diminui a qualidade de anti-aliasing (MSAA) até uma desativação completa.</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Força a Unity a mudar para modelos LOD low-poly a uma distância mais curta da câmara.</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduz o parâmetro <code>Far Clip Plane</code> nas câmaras alvo, retirando objetos distantes da renderização.</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Reduz proporcionalmente a distância de abate (Culling Distance) para camadas de objetos específicos.</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Diminui a frequência dos cálculos de física. Salva a performance durante cargas de física pesadas no navegador.</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>URP Apenas</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduz o tamanho das tabelas LUT de Color Grading ao mínimo.</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Altera o parâmetro <code>meshLodThreshold</code>, introduzido no Unity 6.2, para mudanças de LOD agressivas.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Cuidado com o Physics Step Scaler</p><p>O Scaler de física altera diretamente o parâmetro <code>Time.fixedDeltaTime</code>. Se um controlador de personagem ou mecânica de jogo depender estritamente de frames de física fixos sem interpolação (Interpolation), o movimento de objetos pode ficar &quot;gaguejando&quot; em níveis de baixa qualidade.</p></div><div class="tip custom-block"><p class="custom-block-title">Redefinição das Configurações de Scaler</p><p>Se você experimentou com parâmetros de Scaler (e.g., modificando o <code>Min Bound</code> ou <code>Max Level</code>) e deseja reverter para os valores predefinidos, simplesmente desligue e ligue o interruptor na janela <em>Project Settings</em>. O plugin recriará automaticamente o módulo com as configurações de base.</p></div><h2 id="analise-resolution-scaler" tabindex="-1">Análise: Resolution Scaler <a class="header-anchor" href="#analise-resolution-scaler" aria-label="Permalink to &quot;Análise: Resolution Scaler&quot;">​</a></h2><p>Esta é a ferramenta mais potente do plugin, garantindo o maior aumento de FPS. O seu funcionamento varia drasticamente dependendo do pipeline ativo.</p><h3 id="no-modo-urp-universal-render-pipeline" tabindex="-1">No Modo URP (Universal Render Pipeline) <a class="header-anchor" href="#no-modo-urp-universal-render-pipeline" aria-label="Permalink to &quot;No Modo URP (Universal Render Pipeline)&quot;">​</a></h3><p>No URP, o escalonamento funciona perfeitamente. O plugin interfere diretamente com a propriedade <code>renderScale</code> no <code>UniversalRenderPipelineAsset</code>. A interface (UI) permanece nítida automaticamente, pois o URP é capaz de renderizar o Canvas sobre um mundo 3D escalonado.</p><h3 id="no-modo-birp-built-in-render-pipeline" tabindex="-1">No Modo BiRP (Built-in Render Pipeline) <a class="header-anchor" href="#no-modo-birp-built-in-render-pipeline" aria-label="Permalink to &quot;No Modo BiRP (Built-in Render Pipeline)&quot;">​</a></h3><p>Historicamente, o BiRP carece de uma configuração de Render Scale integrada que funcione em WebGL sem quebrar a interface ou causar falhas (FBO Feedback Loop). O WebAP resolve isso oferecendo duas estratégias exclusivas.</p><h4 id="modo-1-nativebrowserscaling-escala-nativa-do-navegador" tabindex="-1">Modo 1: NativeBrowserScaling (Escala Nativa do Navegador) <a class="header-anchor" href="#modo-1-nativebrowserscaling-escala-nativa-do-navegador" aria-label="Permalink to &quot;Modo 1: NativeBrowserScaling (Escala Nativa do Navegador)&quot;">​</a></h4><p>O plugin escalona o elemento HTML <code>&lt;canvas&gt;</code> diretamente via Native Loop Spoofing (injetando nos parâmetros <code>devicePixelRatio</code> do navegador).</p><ul><li><strong>Prós:</strong> Desempenho máximo, zero overhead do lado da GPU.</li><li><strong>Contras:</strong> A interface do jogo fica desfocada juntamente com os gráficos 3D. Este modo só funciona numa build compilada de WebGL (nenhuma mudança será visível no Unity Editor).</li></ul><h4 id="modo-2-rendertexturescaling" tabindex="-1">Modo 2: RenderTextureScaling <a class="header-anchor" href="#modo-2-rendertexturescaling" aria-label="Permalink to &quot;Modo 2: RenderTextureScaling&quot;">​</a></h4><p>O plugin redireciona a renderização das câmaras alvo para uma textura compartilhada comprimida e utiliza uma Compositor Camera escondida para apresentar a imagem.</p><ul><li><strong>Prós:</strong> O mundo 3D é escalonado, enquanto a UI (texto, botões) permanece cristalina.</li><li><strong>Contras:</strong> Adiciona uma carga marginal à GPU devido à operação Blit (copiando a textura para a tela).</li></ul><div class="info custom-block"><p class="custom-block-title">Corrigindo Cliques do Rato (Raycasts)</p><p>Quando o RenderTextureScaling é utilizado, as coordenadas da tela virtual são comprimidas. Para garantir que os cliques de rato em objetos 3D continuam a funcionar corretamente, o plugin substitui automaticamente componentes padrão de <code>PhysicsRaycaster</code> e <code>Physics2DRaycaster</code> nas câmaras alvo por componentes <code>WebScaledPhysicsRaycaster</code> personalizados. A precisão dos raios (rays) permanece infalível em qualquer escala.</p></div><h2 id="como-preservar-a-clareza-da-ui-para-birp-rendertexturescaling" tabindex="-1">Como Preservar a Clareza da UI? (Para BiRP RenderTextureScaling) <a class="header-anchor" href="#como-preservar-a-clareza-da-ui-para-birp-rendertexturescaling" aria-label="Permalink to &quot;Como Preservar a Clareza da UI? (Para BiRP RenderTextureScaling)&quot;">​</a></h2><p>Para manter a interface nítida enquanto se escalona os gráficos 3D em BiRP com RenderTextureScaling, deve configurar o seu Canvas corretamente. Selecione uma de duas opções:</p><h3 id="opcao-1-screen-space-overlay-recomendada" tabindex="-1">Opção 1: Screen Space - Overlay (Recomendada) <a class="header-anchor" href="#opcao-1-screen-space-overlay-recomendada" aria-label="Permalink to &quot;Opção 1: Screen Space - Overlay (Recomendada)&quot;">​</a></h3><p>O método mais simples e fiável. O plugin gere todo o trabalho automaticamente.</p><ol><li>Selecione o seu <strong>Canvas</strong> na hierarquia da cena.</li><li>No componente Canvas, defina o <strong>Render Mode</strong> para <code>Screen Space - Overlay</code>.<br><em>Resultado:</em> A Unity renderiza a interface em cima do mundo 3D comprimido a uma resolução 100% nativa.</li></ol><h3 id="opcao-2-screen-space-camera-para-camadas-complexas" tabindex="-1">Opção 2: Screen Space - Camera (Para Camadas Complexas) <a class="header-anchor" href="#opcao-2-screen-space-camera-para-camadas-complexas" aria-label="Permalink to &quot;Opção 2: Screen Space - Camera (Para Camadas Complexas)&quot;">​</a></h3><p>Usado se precisar misturar modelos 3D, partículas e UI. Terá de separar a renderização em duas câmaras.</p><ol><li><strong>Câmara Principal (3D):</strong> Certifique-se de que a sua tag está especificada no array de <code>Target Tags</code> do Scaler. No campo <code>Culling Mask</code>, desmarque a camada <strong>UI</strong>. Defina o <code>Depth</code> para <code>0</code>.</li><li><strong>Câmara de UI (Nova):</strong> Crie uma nova câmara para renderizar a interface. <strong>Não</strong> adicione a sua tag às configurações do Scaler. <ul><li>Defina as <code>Clear Flags</code> para <code>Depth Only</code> (para que a câmara não apague o fundo 3D).</li><li>Defina o <code>Culling Mask</code> exclusivamente para a camada <strong>UI</strong>.</li><li>Defina o <code>Depth</code> para <code>1</code> (maior que a câmara principal).</li></ul></li><li><strong>Configuração do Canvas:</strong> Defina o <strong>Render Mode</strong> para <code>Screen Space - Camera</code> e arraste a sua nova Câmara de UI para o slot <code>Render Camera</code>.</li></ol>',28)])])}const g=a(d,[["render",i]]);export{u as __pageData,g as default};
